-- ============================================================================
-- seed_demo.sql
-- ============================================================================
-- Demo data for development. DO NOT RUN IN PRODUCTION.
--
-- Populates two demo events (Coastline Festival, Nightline Club) with their
-- KB sections (133 total) and synthetic orders (39 total).
--
-- All customer phone numbers use the ITU-reserved +999 country code
-- (non-dialable, valid E.164 shape) so that no outbound WhatsApp path can ever
-- message a real person with demo data (audit 8.2). Do NOT change these to real
-- ranges.
--
-- Usage:
--   psql $DATABASE_URL -f supabase/seed/demo.sql
--   or via Supabase CLI: place at supabase/seed.sql for auto-run on db reset
--
-- Linking to your auth user:
--   1. Sign in to /admin via magic link with the email you want to use
--   2. After signup, run:
--      UPDATE operator_users SET user_id = (SELECT id FROM auth.users WHERE email = '<your-email>')
--      WHERE invited_email = '<your-email>';
--
-- Re-running:
--   This script is idempotent. ON CONFLICT clauses ensure re-runs update
--   existing rows rather than failing.
-- ============================================================================

BEGIN;

-- Guard: refuse to seed in production.
DO $$
BEGIN
  IF current_setting('app.environment', true) = 'production' THEN
    RAISE EXCEPTION 'Refusing to seed demo data in production environment';
  END IF;
END $$;

-- This script assumes service-role privileges (BYPASSRLS).
-- If running as a non-service role, prepend: SET LOCAL ROLE postgres;

-- ─── Operators ──────────────────────────────────────────────────────────────
INSERT INTO operators (id, name, legal_entity_name, country_code, default_currency, default_locale)
VALUES
  ('c36bdf70-3489-5ec3-8642-7fde068586cd', 'Coastline Events FZE',
   'Coastline Events FZE', 'AE', 'AED', 'en'),
  ('1444ddec-3690-5e9a-87d6-c0008ad5509d', 'Nightline Hospitality FZE',
   'Nightline Hospitality FZE', 'AE', 'AED', 'en')
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  legal_entity_name = EXCLUDED.legal_entity_name,
  updated_at = now();

-- ─── Operator users ─────────────────────────────────────────────────────────
-- These rows are created with user_id = NULL. Link them to your auth user
-- after first sign-in (see top-of-file instructions).
INSERT INTO operator_users (operator_id, user_id, role, invited_email)
VALUES
  ('c36bdf70-3489-5ec3-8642-7fde068586cd', NULL, 'owner', 'demo@example.com'),
  ('1444ddec-3690-5e9a-87d6-c0008ad5509d', NULL, 'owner', 'demo@example.com')
ON CONFLICT (operator_id, user_id) DO NOTHING;

