-- ─── KB sections: Coastline Festival (65 entries) ─────────────────────────
INSERT INTO kb_sections (event_id, kb_document_id, section_id, category, intent,
  escalation_needed, question_en, answer_en, question_ar, answer_ar, sort_order)
VALUES
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'event.dates', 'Event & Venue Info', 'event_timing', false, 'When does Coastline Festival take place?', 'Coastline Festival runs across two consecutive nights, as listed on the official event page.', 'متى تقام فعالية Coastline Festival؟', 'تقام فعالية Coastline Festival على مدى ليلتين متتاليتين، وفقًا للتواريخ المنشورة على الصفحة الرسمية للفعالية.', 0),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'venue.location', 'Getting Here', 'venue_location', false, 'Where is Coastline Festival located?', 'The festival is held at the designated outdoor festival grounds in the host city. The exact location and map link are available on the official event page.', 'أين تقع فعالية Coastline Festival؟', 'تقام الفعالية في الموقع المخصص للفعاليات في المدينة المضيفة. يمكن الاطلاع على الموقع الدقيق ورابط الخريطة على الصفحة الرسمية للفعالية.', 1),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.age', 'Admission Policies', 'age_eligibility', false, 'What is the minimum age to attend Coastline Festival?', 'The minimum age for entry is 18 years. Valid identification is required at the gate.', 'ما هو الحد الأدنى للسن المسموح به لحضور فعالية Coastline Festival؟', 'الحد الأدنى للسن المسموح به لدخول الفعالية هو 18 عامًا. يُطلب تقديم هوية سارية المفعول عند البوابة.', 2),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.how_to_buy', 'Ticketing', 'other', false, 'How can I purchase a ticket for Coastline Festival?', 'Tickets are sold exclusively through the official ticketing platform. Please use the link provided on the event page to complete your purchase.', 'كيف يمكنني شراء تذكرة لفعالية Coastline Festival؟', 'تُباع التذاكر حصريًا من خلال منصة التذاكر الرسمية. يُرجى استخدام الرابط المتوفر على صفحة الفعالية لإتمام عملية الشراء.', 3),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'event.lineup', 'Lineup', 'lineup_question', false, 'Who is performing at Coastline Festival?', 'The full lineup is published on the official event page and is updated as new artists are confirmed.', 'من هم الفنانون المشاركون في Coastline Festival؟', 'يتم نشر القائمة الكاملة للفنانين على الصفحة الرسمية للفعالية، ويتم تحديثها مع تأكيد كل فنان جديد.', 4),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'event.gate_times', 'Event & Venue Info', 'event_timing', false, 'When do the gates open and close?', 'Gates open at 8:00 PM and close at 2:00 AM on each night of the festival.', 'ما هي مواعيد فتح وإغلاق البوابات؟', 'تفتح البوابات الساعة 8:00 مساءً وتُغلق الساعة 2:00 صباحًا في كل ليلة من ليالي الفعالية.', 5),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'event.last_entry', 'Admission Policies', 'last_entry_time', false, 'What is the last entry time?', 'The last entry time is 2:00 AM. Guests arriving after this time will not be admitted.', 'ما هو آخر موعد للدخول؟', 'آخر موعد للدخول هو الساعة 2:00 صباحًا. لن يُسمح بدخول الضيوف بعد هذا الموعد.', 6),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.id_required', 'Admission Policies', 'entry_policy', false, 'Do I need to bring my ID to enter the festival?', 'Yes. A valid physical or digital government-issued ID is required for entry, and may be requested at any time during the event.', 'هل أحتاج إلى إحضار هويتي للدخول إلى الفعالية؟', 'نعم. يُطلب تقديم هوية حكومية سارية المفعول، سواء كانت مادية أو رقمية، للدخول، وقد يُطلب إبرازها في أي وقت خلال الفعالية.', 7),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.dress_code', 'Admission Policies', 'dress_code', false, 'What is the dress code for Coastline Festival?', 'Smart casual is recommended. Guests are expected to dress in accordance with local customs. Security reserves the right to deny entry to guests in attire deemed inappropriate.', 'ما هو الزي المطلوب لحضور Coastline Festival؟', 'يُفضّل ارتداء الملابس الكاجوال الأنيقة. يُتوقع من الضيوف الالتزام بالعادات والتقاليد المحلية. يحتفظ فريق الأمن بحق رفض دخول أي ضيف يرتدي ملابس غير مناسبة.', 8),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.accessibility', 'Inside the event (Services)', 'other', true, 'Is Coastline Festival accessible for guests with disabilities?', 'The venue provides accessibility accommodations. For specific requirements, please contact the support team in advance so the appropriate arrangements can be made.', 'هل فعالية Coastline Festival مهيأة لذوي الإعاقة؟', 'يوفر الموقع تسهيلات للضيوف من ذوي الإعاقة. للاحتياجات الخاصة، يُرجى التواصل مع فريق الدعم مسبقًا لترتيب الإجراءات المناسبة.', 9),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.first_aid', 'Inside the event (Services)', 'other', false, 'Are first aid services available at the festival?', 'Yes. Trained first aid personnel are available on site throughout the duration of the event.', 'هل تتوفر خدمات الإسعافات الأولية في الفعالية؟', 'نعم. يتوفر موظفون مدربون لتقديم الإسعافات الأولية في الموقع طوال فترة الفعالية.', 10),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.prayer', 'Inside the event (Services)', 'other', false, 'Are there prayer areas at the festival?', 'Yes. Designated prayer areas are located near the main entrance and are available throughout the event.', 'هل تتوفر أماكن للصلاة في الفعالية؟', 'نعم. تتوفر أماكن مخصصة للصلاة بالقرب من المدخل الرئيسي، وهي متاحة طوال فترة الفعالية.', 11),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.smoking', 'Inside the event (Services)', 'other', false, 'Is smoking allowed at the festival?', 'Smoking is permitted in designated areas only. Smoking outside these areas is not allowed.', 'هل يُسمح بالتدخين في الفعالية؟', 'يُسمح بالتدخين في الأماكن المخصصة فقط. التدخين خارج هذه الأماكن غير مسموح به.', 12),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.wifi', 'Inside the event (Services)', 'other', false, 'Is free Wi-Fi available on site?', 'Free Wi-Fi is not provided to general attendees. Mobile data coverage is available on site.', 'هل تتوفر شبكة واي فاي مجانية في الموقع؟', 'لا تتوفر شبكة واي فاي مجانية للحضور العام. تغطية بيانات الهاتف المحمول متوفرة في الموقع.', 13),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.charging', 'Inside the event (Services)', 'other', false, 'Are phone charging stations available at the festival?', 'Phone charging stations are not provided. Guests are encouraged to bring a portable power bank.', 'هل تتوفر محطات لشحن الهواتف في الفعالية؟', 'لا تتوفر محطات شحن للهواتف. يُنصح الضيوف بإحضار بطارية محمولة.', 14),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.merch', 'Inside the event (Services)', 'other', false, 'Will merchandise be available for purchase?', 'Yes. Official merchandise is available for purchase at a dedicated booth at the venue.', 'هل ستتوفر منتجات للبيع في الفعالية؟', 'نعم. تتوفر المنتجات الرسمية للبيع في كشك مخصص داخل الموقع.', 15),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.food', 'Inside the event (Services)', 'other', false, 'What food and drinks are available at the festival?', 'A variety of food and beverage options are available on site, covering common dietary preferences. Outside food and drinks are not permitted.', 'ما هي الأطعمة والمشروبات المتوفرة في الفعالية؟', 'تتوفر مجموعة متنوعة من خيارات الطعام والمشروبات في الموقع، تغطي معظم التفضيلات الغذائية. لا يُسمح بإدخال الأطعمة والمشروبات من خارج الموقع.', 16),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.shisha', 'Inside the event (Services)', 'other', false, 'Will shisha be available at the festival?', 'Shisha is not available at this event.', 'هل ستتوفر الشيشة في الفعالية؟', 'لا تتوفر الشيشة في هذه الفعالية.', 17),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.info_booth', 'Inside the event (Services)', 'other', false, 'Are there information booths at the festival?', 'Yes. Information booths are located near the main entrance and within the event grounds.', 'هل تتوفر أكشاك معلومات في الفعالية؟', 'نعم. تتوفر أكشاك المعلومات بالقرب من المدخل الرئيسي وداخل أرض الفعالية.', 18),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.atm', 'Inside the event (Services)', 'other', false, 'Are ATMs available on site?', 'ATMs are not available on site. The event is cashless, and payments are accepted by card and mobile wallet only.', 'هل تتوفر أجهزة صراف آلي في الموقع؟', 'لا تتوفر أجهزة صراف آلي في الموقع. الفعالية لا تتعامل بالنقد، وتُقبل المدفوعات بالبطاقات والمحافظ الإلكترونية فقط.', 19),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'payment.methods_onsite', 'Event & Venue Info', 'other', false, 'What payment methods are accepted at the festival?', 'This is a cashless event. Accepted payment methods include major credit and debit cards and supported mobile wallets.', 'ما هي طرق الدفع المقبولة في الفعالية؟', 'هذه فعالية لا تتعامل بالنقد. تشمل طرق الدفع المقبولة بطاقات الائتمان والخصم الرئيسية والمحافظ الإلكترونية المدعومة.', 20),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.washrooms', 'Inside the event (Services)', 'other', false, 'Are washrooms available at the festival?', 'Yes. Washrooms are available throughout the venue.', 'هل تتوفر دورات مياه في الفعالية؟', 'نعم. تتوفر دورات المياه في جميع أنحاء الموقع.', 21),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.lost_found_onsite', 'Inside the event (Services)', 'other', true, 'Does the festival have a lost and found service?', 'Yes. Lost items can be handed in at the information booth, and recovered items can be claimed there. For items not recovered during the event, please contact the support team.', 'هل تتوفر خدمة المفقودات في الفعالية؟', 'نعم. يمكن تسليم الأغراض المفقودة في كشك المعلومات، ويمكن استلام الأغراض المعثور عليها من هناك. للأغراض التي لم يتم استلامها خلال الفعالية، يُرجى التواصل مع فريق الدعم.', 22),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.lost_found_post_event', 'Inside the event (Services)', 'other', true, 'How can I contact lost and found after the event?', 'Please reach out to the support team through the official channels listed on the event page. Unclaimed items are held for a limited period.', 'كيف يمكنني التواصل مع خدمة المفقودات بعد انتهاء الفعالية؟', 'يُرجى التواصل مع فريق الدعم عبر القنوات الرسمية المدرجة على صفحة الفعالية. يتم الاحتفاظ بالأغراض غير المُطالب بها لفترة محدودة.', 23),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'service.found_item', 'Inside the event (Services)', 'other', false, 'What should I do if I find someone else''s item?', 'Please hand the item in at any information booth on the festival grounds.', 'ماذا أفعل إذا وجدت غرضًا يخص شخصًا آخر؟', 'يُرجى تسليم الغرض في أي كشك معلومات داخل أرض الفعالية.', 24),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.prohibited_items', 'Admission Policies', 'entry_policy', false, 'Which items are prohibited at the festival?', 'Prohibited items include weapons, illegal substances, outside food and beverages, glass containers, large bags, professional cameras, drones, lasers, and any item that may pose a safety risk. The full list is published on the official event page.', 'ما هي الأشياء الممنوع إحضارها إلى الفعالية؟', 'تشمل الممنوعات الأسلحة والمواد غير المشروعة والأطعمة والمشروبات من خارج الموقع والعبوات الزجاجية والحقائب الكبيرة وكاميرات التصوير الاحترافية والطائرات بدون طيار وأشعة الليزر وأي غرض قد يُشكّل خطرًا. تُنشر القائمة الكاملة على الصفحة الرسمية للفعالية.', 25),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.prohibited_consequence', 'Admission Policies', 'entry_policy', true, 'What happens if I am found with a prohibited item?', 'Security will ask you to dispose of the item or return it to your vehicle. Repeated or serious violations may result in denial of entry without refund.', 'ماذا يحدث إذا وُجد بحوزتي غرض ممنوع؟', 'سيُطلب منك التخلص من الغرض أو إعادته إلى سيارتك. قد تؤدي المخالفات المتكررة أو الجسيمة إلى رفض الدخول دون استرداد ثمن التذكرة.', 26),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.bag_check', 'Admission Policies', 'entry_policy', false, 'Will my bag be checked at the entrance?', 'Yes. All bags are subject to security screening at the entrance.', 'هل سيتم تفتيش حقيبتي عند الدخول؟', 'نعم. تخضع جميع الحقائب للتفتيش الأمني عند الدخول.', 27),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.luggage_airport', 'Admission Policies', 'entry_policy', true, 'I am coming straight from the airport. Can I bring my luggage to the festival?', 'Large luggage is not permitted inside the festival grounds. Please store your luggage before arrival. If this is not possible, contact the support team for guidance.', 'أنا قادم مباشرة من المطار. هل يمكنني إحضار حقائبي إلى الفعالية؟', 'لا يُسمح بإدخال الحقائب الكبيرة إلى أرض الفعالية. يُرجى تخزين حقائبك قبل الوصول. إذا تعذر ذلك، يُرجى التواصل مع فريق الدعم للحصول على إرشادات.', 28),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'safety.unsafe_situation', 'Inside the event (Services)', 'other', true, 'I am in an uncomfortable or unsafe situation on site. What should I do?', 'Please go to the nearest information booth, approach any staff member wearing event identification, or call the on-site safety number listed on your wristband or the event page. Your safety is the top priority.', 'أنا في موقف غير مريح أو غير آمن داخل الموقع. ماذا أفعل؟', 'يُرجى التوجه إلى أقرب كشك معلومات، أو التحدث إلى أي موظف يرتدي شارة الفعالية، أو الاتصال برقم الأمان الميداني المدرج على سوار اليد أو على صفحة الفعالية. سلامتك هي الأولوية القصوى.', 29),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.photo_video', 'Inside the event (Services)', 'other', false, 'What is the policy on photos and video recording at the festival?', 'Personal photography and recording for non-commercial use is permitted. Professional cameras, drones, and commercial recording equipment require prior authorization.', 'ما هي سياسة التصوير والتسجيل في الفعالية؟', 'يُسمح بالتصوير والتسجيل الشخصي لأغراض غير تجارية. تتطلب الكاميرات الاحترافية والطائرات بدون طيار ومعدات التسجيل التجاري إذنًا مسبقًا.', 30),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'getting_here.parking', 'Getting Here', 'other', false, 'Is parking available at the venue?', 'Yes. Designated parking areas are available near the venue. Please refer to the venue map for parking entry points.', 'هل تتوفر مواقف سيارات في الموقع؟', 'نعم. تتوفر مواقف مخصصة بالقرب من الموقع. يُرجى الرجوع إلى خريطة الموقع لمعرفة مداخل المواقف.', 31),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'getting_here.walking', 'Getting Here', 'other', false, 'Is the parking within walking distance of the entrance?', 'Yes. Parking areas are within walking distance of the main entrance. Shuttle service may be provided depending on parking location.', 'هل المواقف على مسافة قريبة من المدخل؟', 'نعم. تقع المواقف على مسافة سير من المدخل الرئيسي. قد تتوفر خدمة نقل مكوكي حسب موقع المواقف.', 32),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.tiers_overview', 'Ticketing', 'ticket_availability_sold_out', false, 'What ticket tiers are available for Coastline Festival?', 'Two ticket tiers are available: General Admission and Backstage. Each tier offers a different level of access and amenities. Full details are listed on the official event page.', 'ما هي فئات التذاكر المتوفرة لفعالية Coastline Festival؟', 'تتوفر فئتان من التذاكر: الدخول العام (General Admission) والباكستيج (Backstage). توفر كل فئة مستوى مختلفًا من الوصول والمزايا. التفاصيل الكاملة على الصفحة الرسمية للفعالية.', 33),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.ga_inclusions', 'Ticketing', 'ticket_availability_sold_out', false, 'What does a General Admission ticket include?', 'General Admission grants entry to all public areas of the festival, including the main stage and general food and beverage zones.', 'ماذا تتضمن تذكرة الدخول العام؟', 'تمنح تذكرة الدخول العام حق الوصول إلى جميع المناطق العامة في الفعالية، بما في ذلك المسرح الرئيسي ومناطق الطعام والمشروبات العامة.', 34),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.backstage_inclusions', 'Ticketing', 'backstage_or_vib_request', true, 'What does a Backstage ticket include?', 'A Backstage ticket includes all General Admission access plus entry to the elevated backstage viewing area and dedicated bar service. Exact inclusions are listed on the event page.', 'ماذا تتضمن تذكرة الباكستيج؟', 'تتضمن تذكرة الباكستيج جميع امتيازات الدخول العام، بالإضافة إلى الدخول إلى منطقة المشاهدة المرتفعة في الباكستيج وخدمة بار مخصصة. التفاصيل الدقيقة على صفحة الفعالية.', 35),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.backstage_capacity', 'Ticketing', 'backstage_or_vib_request', true, 'Is there a capacity limit on Backstage access?', 'Yes. Backstage access is capacity-limited and typically sells out before General Admission.', 'هل هناك حد أقصى لعدد الحاضرين في منطقة الباكستيج؟', 'نعم. منطقة الباكستيج محدودة السعة وعادةً ما تُباع تذاكرها قبل تذاكر الدخول العام.', 36),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.multi_event', 'Ticketing', 'ticket_availability_sold_out', false, 'Does one ticket grant access to multiple events?', 'No. Each ticket is valid for the specific event and date printed on it.', 'هل تمنح تذكرة واحدة الوصول إلى عدة فعاليات؟', 'لا. كل تذكرة صالحة للفعالية والتاريخ المحددين عليها فقط.', 37),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.wallet_credit', 'Ticketing', 'other', true, 'How do I use wallet credit toward a purchase?', 'Wallet credit can be applied at checkout if available on your account. If the credit is not appearing or you have a question about your balance, please contact the support team.', 'كيف أستخدم رصيد المحفظة عند الشراء؟', 'يمكن تطبيق رصيد المحفظة عند إتمام عملية الشراء إذا كان متاحًا في حسابك. إذا لم يظهر الرصيد أو كان لديك استفسار عن رصيدك، يُرجى التواصل مع فريق الدعم.', 38),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.delivery_timing', 'Ticketing', 'ticket_delivery_issue', false, 'When will I receive my ticket after purchase?', 'Tickets are delivered to your account on the official ticketing platform immediately after a successful purchase. A confirmation email is sent to the email address used at checkout.', 'متى سأستلم تذكرتي بعد الشراء؟', 'تُسلّم التذاكر إلى حسابك على منصة التذاكر الرسمية فور إتمام عملية الشراء بنجاح. يتم إرسال رسالة تأكيد إلى البريد الإلكتروني المستخدم عند الشراء.', 39),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.buying_for_friends', 'Ticketing', 'other', false, 'Can I buy tickets for friends?', 'Yes. You can purchase multiple tickets in a single order. Each ticket can then be transferred to the recipient through the official ticketing platform.', 'هل يمكنني شراء تذاكر لأصدقائي؟', 'نعم. يمكنك شراء عدة تذاكر في طلب واحد. يمكن بعد ذلك تحويل كل تذكرة إلى المستلم عبر منصة التذاكر الرسمية.', 40),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.cancel_transfer', 'Ticketing', 'other', true, 'How do I cancel a ticket transfer I sent to a friend?', 'If the recipient has not yet accepted the transfer, you may cancel it from your account. If it has already been accepted, please contact the support team.', 'كيف يمكنني إلغاء تحويل تذكرة قمت بإرسالها إلى صديق؟', 'إذا لم يقبل المستلم التحويل بعد، يمكنك إلغاؤه من حسابك. إذا تم قبوله بالفعل، يُرجى التواصل مع فريق الدعم.', 41),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.offline_access', 'Ticketing', 'ticket_delivery_issue', false, 'I will not have data or Wi-Fi at the venue. How do I access my ticket?', 'Please download your ticket to your device before arriving. Once downloaded, the QR code can be displayed without an internet connection.', 'لن يكون لدي بيانات أو واي فاي في الموقع. كيف أصل إلى تذكرتي؟', 'يُرجى تنزيل تذكرتك على جهازك قبل الوصول. بعد التنزيل، يمكن عرض رمز الاستجابة السريعة دون الحاجة إلى اتصال بالإنترنت.', 42),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.reseller', 'Ticketing', 'ticket_delivery_issue', true, 'I purchased my ticket through a reseller. How do I access it?', 'If you purchased through an authorized reseller, follow the instructions in their confirmation email to claim your ticket on the official ticketing platform. If you encounter issues, contact the support team with your reseller order details.', 'اشتريت تذكرتي عبر جهة إعادة بيع. كيف أصل إليها؟', 'إذا اشتريت عبر جهة إعادة بيع معتمدة، اتبع التعليمات في رسالة التأكيد الخاصة بهم لاستلام تذكرتك على منصة التذاكر الرسمية. إذا واجهت مشكلة، تواصل مع فريق الدعم مع تفاصيل طلبك.', 43),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'payment.methods_online', 'Ticketing', 'other', false, 'What payment methods are accepted for online ticket purchases?', 'Major credit and debit cards and supported mobile wallets are accepted at checkout.', 'ما هي طرق الدفع المقبولة لشراء التذاكر عبر الإنترنت؟', 'تُقبل بطاقات الائتمان والخصم الرئيسية والمحافظ الإلكترونية المدعومة عند إتمام عملية الشراء.', 44),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.group_discount', 'Ticketing', 'other', false, 'Are group discounts available?', 'Group discounts are not offered for this event.', 'هل تتوفر خصومات للمجموعات؟', 'لا تتوفر خصومات للمجموعات في هذه الفعالية.', 45),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.max_quantity', 'Ticketing', 'other', false, 'What is the maximum number of tickets I can purchase?', 'Each customer may purchase up to a defined limit per order, listed on the checkout page. This limit is in place to prevent bulk resale.', 'ما هو الحد الأقصى لعدد التذاكر التي يمكنني شراؤها؟', 'يمكن لكل عميل شراء عدد محدود من التذاكر لكل طلب، كما هو مذكور في صفحة الدفع. هذا الحد موجود لمنع إعادة البيع بكميات كبيرة.', 46),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.resale', 'Ticketing', 'other', true, 'Is there an official channel to resell my ticket?', 'Official ticket resale is available within the ticketing platform where supported. Tickets sold outside the official platform are not guaranteed to be valid.', 'هل توجد قناة رسمية لإعادة بيع تذكرتي؟', 'تتوفر إعادة البيع الرسمية داخل منصة التذاكر حيثما كانت مدعومة. التذاكر التي تُباع خارج المنصة الرسمية لا يُضمن صلاحيتها.', 47),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'support.contact', 'Ticketing', 'other', true, 'Who do I contact for ticket support?', 'Please contact the support team through the official channels listed on the event page. Include your order ID for the fastest response.', 'بمن يجب أن أتواصل للحصول على دعم بخصوص تذكرتي؟', 'يُرجى التواصل مع فريق الدعم عبر القنوات الرسمية المدرجة على صفحة الفعالية. يُرجى تضمين رقم الطلب للحصول على استجابة أسرع.', 48),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.change_details', 'Ticketing', 'other', true, 'How can I change my details after purchase?', 'Some details, such as the ticket holder''s name, may be editable from your account. For changes that are not available in the platform, please contact the support team.', 'كيف يمكنني تغيير بياناتي بعد إتمام عملية الشراء؟', 'يمكن تعديل بعض التفاصيل، مثل اسم حامل التذكرة، من حسابك. للتغييرات غير المتاحة في المنصة، يُرجى التواصل مع فريق الدعم.', 49),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.change_date', 'Ticketing', 'other', true, 'Can I change my ticket to a different date?', 'Date changes are subject to the event''s transfer policy and may not be possible for all ticket tiers. Please contact the support team to review your options.', 'هل يمكنني تغيير تذكرتي إلى تاريخ آخر؟', 'يخضع تغيير التاريخ لسياسة التحويل الخاصة بالفعالية وقد لا يكون متاحًا لجميع فئات التذاكر. يُرجى التواصل مع فريق الدعم لمراجعة الخيارات المتاحة لك.', 50),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.upgrade', 'Ticketing', 'ticket_upgrade_request', true, 'Can I upgrade my ticket?', 'Upgrades from a lower tier to a higher tier may be possible subject to availability. Please contact the support team to request an upgrade.', 'هل يمكنني ترقية تذكرتي؟', 'قد تكون ترقية التذكرة من فئة أدنى إلى فئة أعلى ممكنة وفقًا للتوفر. يُرجى التواصل مع فريق الدعم لطلب الترقية.', 51),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.upgrade_foc', 'Ticketing', 'ticket_upgrade_request', true, 'Can I upgrade a complimentary ticket to a paid tier?', 'Complimentary tickets are generally not eligible for paid upgrades. Please contact the support team for case-by-case review.', 'هل يمكنني ترقية تذكرة مجانية إلى فئة مدفوعة؟', 'التذاكر المجانية بشكل عام غير مؤهلة للترقية المدفوعة. يُرجى التواصل مع فريق الدعم للمراجعة في كل حالة على حدة.', 52),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.cancel_request', 'Ticketing', 'refund_request', true, 'Can I cancel my ticket?', 'Cancellation eligibility is determined by the event''s refund policy, which is published on the official event page. If your purchase falls within the eligible window, please contact the support team to request a cancellation.', 'هل يمكنني إلغاء تذكرتي؟', 'تتحدد أهلية الإلغاء وفقًا لسياسة الاسترداد الخاصة بالفعالية المنشورة على الصفحة الرسمية. إذا كانت عملية الشراء ضمن الفترة المؤهلة، يُرجى التواصل مع فريق الدعم لطلب الإلغاء.', 53),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.no_confirmation', 'Ticketing', 'payment_incomplete', true, 'I purchased a ticket but did not receive a confirmation email. What should I do?', 'Please check your spam or junk folder first. If you do not find the email, contact the support team with your order ID or the email address used at checkout.', 'اشتريت تذكرة لكنني لم أستلم رسالة التأكيد. ماذا أفعل؟', 'يُرجى التحقق من مجلد البريد العشوائي أو غير المرغوب فيه أولًا. إذا لم تجد الرسالة، تواصل مع فريق الدعم مع تقديم رقم الطلب أو البريد الإلكتروني المستخدم عند الشراء.', 54),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.not_received', 'Ticketing', 'ticket_delivery_issue', true, 'I have not received my ticket. What should I do?', 'Tickets are delivered to your account on the official ticketing platform. Please log in and check your tickets section. If your ticket is not there, contact the support team with your order details.', 'لم أستلم تذكرتي. ماذا أفعل؟', 'تُسلّم التذاكر إلى حسابك على منصة التذاكر الرسمية. يُرجى تسجيل الدخول والتحقق من قسم التذاكر. إذا لم تكن تذكرتك موجودة، تواصل مع فريق الدعم مع تقديم تفاصيل طلبك.', 55),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.add_more', 'Ticketing', 'other', true, 'Can I add more tickets to an order that has already been processed?', 'Once an order has been processed it cannot be modified. You may place a new order subject to availability.', 'هل يمكنني إضافة تذاكر إلى طلب تم تنفيذه بالفعل؟', 'بعد تنفيذ الطلب، لا يمكن تعديله. يمكنك تقديم طلب جديد وفقًا للتوفر.', 56),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.transfer', 'Ticketing', 'other', false, 'Are tickets transferable to family or friends?', 'Yes. Tickets can be transferred to another person through the official ticketing platform up until the event start time.', 'هل التذاكر قابلة للتحويل إلى العائلة أو الأصدقاء؟', 'نعم. يمكن تحويل التذاكر إلى شخص آخر عبر منصة التذاكر الرسمية حتى وقت بدء الفعالية.', 57),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.delivery_method', 'Ticketing', 'ticket_delivery_issue', false, 'Can I receive my ticket by email, SMS, or WhatsApp?', 'Tickets are delivered through your account on the official ticketing platform. Confirmation messages may be sent by email, but the active ticket is held in your account.', 'هل يمكنني استلام تذكرتي عبر البريد الإلكتروني أو الرسائل النصية أو الواتساب؟', 'تُسلّم التذاكر عبر حسابك على منصة التذاكر الرسمية. قد تُرسل رسائل التأكيد عبر البريد الإلكتروني، لكن التذكرة الفعلية محفوظة في حسابك.', 58),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.mail_physical', 'Ticketing', 'ticket_delivery_issue', false, 'Can my ticket be mailed to me as a physical copy?', 'No. Tickets are digital only and are accessed through the official ticketing platform.', 'هل يمكن إرسال تذكرتي بالبريد كنسخة ورقية؟', 'لا. التذاكر رقمية فقط ويتم الوصول إليها عبر منصة التذاكر الرسمية.', 59),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'ticket.upload_issue', 'Ticketing', 'ticket_delivery_issue', true, 'My ticket is not loading in the app. What should I do?', 'Please ensure you are logged in with the email address used at purchase and that the app is updated to the latest version. If the issue persists, contact the support team.', 'تذكرتي لا تظهر في التطبيق. ماذا أفعل؟', 'يُرجى التأكد من تسجيل الدخول بالبريد الإلكتروني المستخدم عند الشراء وأن التطبيق محدّث إلى أحدث إصدار. إذا استمرت المشكلة، تواصل مع فريق الدعم.', 60),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.refund.standard', 'Ticketing', 'refund_request', true, 'What is the refund policy for Coastline Festival?', 'All ticket sales are final. Refunds are not issued except where required by applicable consumer protection law or in cases of event cancellation or material change. Refund eligibility is reviewed on a case-by-case basis by the support team.', 'ما هي سياسة استرداد المبالغ لفعالية Coastline Festival؟', 'جميع مبيعات التذاكر نهائية. لا يتم استرداد المبالغ إلا في الحالات التي يقتضيها قانون حماية المستهلك المعمول به أو في حالات إلغاء الفعالية أو إجراء تغيير جوهري عليها. يُراجع فريق الدعم أهلية الاسترداد لكل حالة على حدة.', 61),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.refund.medical', 'Ticketing', 'refund_request', true, 'I cannot attend due to a medical reason. Can I get a refund?', 'Medical exceptions are reviewed on a case-by-case basis with valid supporting documentation. Please contact the support team in advance of the event with your order details and documentation.', 'لا أستطيع الحضور بسبب ظرف صحي. هل يمكنني استرداد قيمة التذكرة؟', 'تُراجع الاستثناءات الصحية لكل حالة على حدة مع تقديم وثائق ثبوتية صالحة. يُرجى التواصل مع فريق الدعم قبل موعد الفعالية مع تقديم تفاصيل طلبك والوثائق المطلوبة.', 62),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.refund.event_change', 'Ticketing', 'compensation_request', true, 'The event date or format has changed. Am I eligible for a refund?', 'If the event has been materially changed, ticket holders may be eligible for a refund or compensation. The support team will reach out with the available options, or you can contact them with your order details.', 'تم تغيير تاريخ الفعالية أو شكلها. هل أنا مؤهل لاسترداد المبلغ؟', 'إذا تم إجراء تغيير جوهري على الفعالية، قد يكون حاملو التذاكر مؤهلين لاسترداد المبلغ أو الحصول على تعويض. سيتواصل فريق الدعم معك بالخيارات المتاحة، أو يمكنك التواصل معهم مع تقديم تفاصيل طلبك.', 63),
  ('a9107667-93da-56fb-aaaf-b6d5f6d723bf', 'cc40a1df-b83a-5831-8043-fa754b89f88d', 'policy.refund.denied_entry', 'Ticketing', 'refund_request', true, 'I was denied entry. Can I get a refund?', 'Entry decisions made by venue security are final and refunds are not typically issued for denied entry due to policy violations. Each case is reviewed individually by the support team.', 'تم منعي من الدخول. هل يمكنني استرداد قيمة التذكرة؟', 'قرارات الدخول التي يتخذها فريق أمن الموقع نهائية، ولا تُسترد عادةً قيمة التذاكر في حالات منع الدخول بسبب مخالفة السياسات. يُراجع فريق الدعم كل حالة على حدة.', 64)
ON CONFLICT (event_id, section_id) DO UPDATE SET
  category = EXCLUDED.category,
  intent = EXCLUDED.intent,
  escalation_needed = EXCLUDED.escalation_needed,
  question_en = EXCLUDED.question_en,
  answer_en = EXCLUDED.answer_en,
  question_ar = EXCLUDED.question_ar,
  answer_ar = EXCLUDED.answer_ar,
  sort_order = EXCLUDED.sort_order;

-- ─── KB sections: Nightline Club (68 entries) ─────────────────────────
INSERT INTO kb_sections (event_id, kb_document_id, section_id, category, intent,
  escalation_needed, question_en, answer_en, question_ar, answer_ar, sort_order)
VALUES
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'event.dates', 'Event & Venue Info', 'event_timing', false, 'When does Nightline Club take place?', 'Nightline Club is a single-night event. The exact date is published on the official event page.', 'متى تقام فعالية Nightline Club؟', 'Nightline Club فعالية لليلة واحدة. يُنشر التاريخ الدقيق على الصفحة الرسمية للفعالية.', 0),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'venue.location', 'Getting Here', 'venue_location', false, 'Where is Nightline Club located?', 'The event is held at a designated venue in the host city. The exact location and map link are available on the official event page.', 'أين تقع فعالية Nightline Club؟', 'تقام الفعالية في موقع مخصص في المدينة المضيفة. يمكن الاطلاع على الموقع الدقيق ورابط الخريطة على الصفحة الرسمية للفعالية.', 1),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.age', 'Admission Policies', 'age_eligibility', false, 'What is the minimum age to attend Nightline Club?', 'The minimum age for entry is 21 years. Valid identification is required at the gate, and entry will be denied without it.', 'ما هو الحد الأدنى للسن المسموح به لحضور فعالية Nightline Club؟', 'الحد الأدنى للسن المسموح به لدخول الفعالية هو 21 عامًا. يُطلب تقديم هوية سارية المفعول عند البوابة، ولن يُسمح بالدخول بدونها.', 2),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.how_to_buy', 'Ticketing', 'other', false, 'How can I purchase a ticket for Nightline Club?', 'Tickets are sold exclusively through the official ticketing platform. Please use the link provided on the event page to complete your purchase.', 'كيف يمكنني شراء تذكرة لفعالية Nightline Club؟', 'تُباع التذاكر حصريًا من خلال منصة التذاكر الرسمية. يُرجى استخدام الرابط المتوفر على صفحة الفعالية لإتمام عملية الشراء.', 3),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'event.lineup', 'Lineup', 'lineup_question', false, 'Who is performing at Nightline Club?', 'The lineup is published on the official event page and is updated as artists are confirmed.', 'من هم الفنانون المشاركون في Nightline Club؟', 'تُنشر قائمة الفنانين على الصفحة الرسمية للفعالية، ويتم تحديثها مع تأكيد كل فنان.', 4),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'event.stages', 'Event & Venue Info', 'other', false, 'How many stages or areas will there be at the event?', 'The number of stages or performance areas is listed on the official event page along with the schedule.', 'كم عدد المسارح أو المناطق الموسيقية في الفعالية؟', 'يُذكر عدد المسارح أو المناطق الموسيقية على الصفحة الرسمية للفعالية مع الجدول الزمني.', 5),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'event.gate_times', 'Event & Venue Info', 'event_timing', false, 'When do the doors open and close?', 'Doors open at 10:00 PM and the event runs until 4:00 AM.', 'ما هي مواعيد فتح وإغلاق الأبواب؟', 'تفتح الأبواب الساعة 10:00 مساءً وتستمر الفعالية حتى الساعة 4:00 صباحًا.', 6),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'event.last_entry', 'Admission Policies', 'last_entry_time', false, 'What is the last entry time?', 'The last entry time is 1:30 AM. Guests arriving after this time will not be admitted.', 'ما هو آخر موعد للدخول؟', 'آخر موعد للدخول هو الساعة 1:30 صباحًا. لن يُسمح بدخول الضيوف بعد هذا الموعد.', 7),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.id_required', 'Admission Policies', 'entry_policy', false, 'Do I need to bring my ID to enter?', 'Yes. A valid physical or digital government-issued ID is required for entry. Entry will be denied without valid identification.', 'هل أحتاج إلى إحضار هويتي للدخول؟', 'نعم. يُطلب تقديم هوية حكومية سارية المفعول، سواء كانت مادية أو رقمية، للدخول. لن يُسمح بالدخول دون هوية سارية.', 8),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.dress_code', 'Admission Policies', 'dress_code', false, 'What is the dress code for Nightline Club?', 'Smart attire is required. Athletic wear, beach attire, and overly casual clothing are not permitted. Security reserves the right to deny entry to guests in attire deemed inappropriate.', 'ما هو الزي المطلوب لحضور Nightline Club؟', 'يُطلب ارتداء الملابس الأنيقة. الملابس الرياضية وملابس الشاطئ والملابس الكاجوال غير مسموح بها. يحتفظ فريق الأمن بحق رفض دخول أي ضيف يرتدي ملابس غير مناسبة.', 9),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.accessibility', 'Inside the event (Services)', 'other', true, 'Is Nightline Club accessible for guests with disabilities?', 'The venue provides accessibility accommodations where possible. For specific requirements, please contact the support team in advance.', 'هل فعالية Nightline Club مهيأة لذوي الإعاقة؟', 'يوفر الموقع تسهيلات للضيوف من ذوي الإعاقة عند الإمكان. للاحتياجات الخاصة، يُرجى التواصل مع فريق الدعم مسبقًا.', 10),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.first_aid', 'Inside the event (Services)', 'other', false, 'Are first aid services available?', 'Yes. Trained first aid personnel are on site throughout the event.', 'هل تتوفر خدمات الإسعافات الأولية؟', 'نعم. يتوفر موظفون مدربون لتقديم الإسعافات الأولية في الموقع طوال فترة الفعالية.', 11),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.prayer', 'Inside the event (Services)', 'other', false, 'Are there prayer areas at the venue?', 'A designated prayer area is available near the venue entrance.', 'هل تتوفر أماكن للصلاة في الموقع؟', 'تتوفر منطقة مخصصة للصلاة بالقرب من مدخل الموقع.', 12),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.smoking', 'Inside the event (Services)', 'other', false, 'Is smoking allowed at the venue?', 'Smoking is permitted in designated outdoor areas only.', 'هل يُسمح بالتدخين في الموقع؟', 'يُسمح بالتدخين في الأماكن الخارجية المخصصة فقط.', 13),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.wifi', 'Inside the event (Services)', 'other', false, 'Is free Wi-Fi available?', 'Free Wi-Fi is not provided. Mobile data coverage is available on site.', 'هل تتوفر شبكة واي فاي مجانية؟', 'لا تتوفر شبكة واي فاي مجانية. تغطية بيانات الهاتف المحمول متوفرة في الموقع.', 14),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.charging', 'Inside the event (Services)', 'other', false, 'Are phone charging stations available?', 'Phone charging stations are not provided. Guests are encouraged to bring a portable power bank.', 'هل تتوفر محطات لشحن الهواتف؟', 'لا تتوفر محطات شحن للهواتف. يُنصح الضيوف بإحضار بطارية محمولة.', 15),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.merch', 'Inside the event (Services)', 'other', false, 'Will merchandise be available?', 'Official merchandise may be available at the venue. Availability is announced through the official channels.', 'هل ستتوفر منتجات للبيع؟', 'قد تتوفر منتجات رسمية في الموقع. يتم الإعلان عن التوفر عبر القنوات الرسمية.', 16),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.food', 'Inside the event (Services)', 'other', false, 'What food and drinks are available?', 'A selection of food and beverages is available at the venue. Outside food and drinks are not permitted.', 'ما هي الأطعمة والمشروبات المتوفرة؟', 'تتوفر مجموعة مختارة من الطعام والمشروبات في الموقع. لا يُسمح بإدخال الأطعمة والمشروبات من خارج الموقع.', 17),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.shisha', 'Inside the event (Services)', 'other', false, 'Will shisha be available?', 'Shisha is not available at this event.', 'هل ستتوفر الشيشة؟', 'لا تتوفر الشيشة في هذه الفعالية.', 18),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.info_booth', 'Inside the event (Services)', 'other', false, 'Is there an information booth at the venue?', 'Yes. An information desk is located near the main entrance.', 'هل يوجد كشك معلومات في الموقع؟', 'نعم. يوجد مكتب معلومات بالقرب من المدخل الرئيسي.', 19),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.atm', 'Inside the event (Services)', 'other', false, 'Are ATMs available on site?', 'ATMs are not available on site. The event is cashless.', 'هل تتوفر أجهزة صراف آلي في الموقع؟', 'لا تتوفر أجهزة صراف آلي في الموقع. الفعالية لا تتعامل بالنقد.', 20),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'payment.methods_onsite', 'Event & Venue Info', 'other', false, 'What payment methods are accepted at the venue?', 'This is a cashless event. Accepted methods include major credit and debit cards and supported mobile wallets.', 'ما هي طرق الدفع المقبولة في الموقع؟', 'هذه فعالية لا تتعامل بالنقد. تشمل الطرق المقبولة بطاقات الائتمان والخصم الرئيسية والمحافظ الإلكترونية المدعومة.', 21),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.washrooms', 'Inside the event (Services)', 'other', false, 'Are washrooms available?', 'Yes. Washrooms are available throughout the venue.', 'هل تتوفر دورات مياه؟', 'نعم. تتوفر دورات المياه في جميع أنحاء الموقع.', 22),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.lost_found_onsite', 'Inside the event (Services)', 'other', true, 'Does the venue have a lost and found service?', 'Yes. Lost items can be handed in at the information desk. For items not recovered during the event, please contact the support team afterward.', 'هل تتوفر خدمة المفقودات في الموقع؟', 'نعم. يمكن تسليم الأغراض المفقودة إلى مكتب المعلومات. للأغراض التي لم يتم استلامها خلال الفعالية، يُرجى التواصل مع فريق الدعم بعد ذلك.', 23),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.lost_found_post_event', 'Inside the event (Services)', 'other', true, 'How can I contact lost and found after the event?', 'Please contact the support team through the official channels listed on the event page. Unclaimed items are held for a limited period.', 'كيف يمكنني التواصل مع خدمة المفقودات بعد انتهاء الفعالية؟', 'يُرجى التواصل مع فريق الدعم عبر القنوات الرسمية المدرجة على صفحة الفعالية. يتم الاحتفاظ بالأغراض غير المُطالب بها لفترة محدودة.', 24),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'service.found_item', 'Inside the event (Services)', 'other', false, 'What should I do if I find someone else''s item?', 'Please hand the item in at the information desk inside the venue.', 'ماذا أفعل إذا وجدت غرضًا يخص شخصًا آخر؟', 'يُرجى تسليم الغرض إلى مكتب المعلومات داخل الموقع.', 25),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.prohibited_items', 'Admission Policies', 'entry_policy', false, 'Which items are prohibited at the venue?', 'Prohibited items include weapons, illegal substances, outside food and beverages, glass containers, large bags, professional cameras, and any item that may pose a safety or comfort risk. The full list is published on the official event page.', 'ما هي الأشياء الممنوع إحضارها إلى الموقع؟', 'تشمل الممنوعات الأسلحة والمواد غير المشروعة والأطعمة والمشروبات من خارج الموقع والعبوات الزجاجية والحقائب الكبيرة وكاميرات التصوير الاحترافية وأي غرض قد يُشكّل خطرًا على السلامة أو الراحة. القائمة الكاملة منشورة على الصفحة الرسمية للفعالية.', 26),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.prohibited_consequence', 'Admission Policies', 'entry_policy', true, 'What happens if I am found with a prohibited item?', 'Security will ask you to dispose of the item or return it to your vehicle. Repeated or serious violations may result in denial of entry without refund.', 'ماذا يحدث إذا وُجد بحوزتي غرض ممنوع؟', 'سيُطلب منك التخلص من الغرض أو إعادته إلى سيارتك. قد تؤدي المخالفات المتكررة أو الجسيمة إلى رفض الدخول دون استرداد ثمن التذكرة.', 27),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.bag_check', 'Admission Policies', 'entry_policy', false, 'Will my bag be checked at the entrance?', 'Yes. All bags are subject to security screening at the entrance.', 'هل سيتم تفتيش حقيبتي عند الدخول؟', 'نعم. تخضع جميع الحقائب للتفتيش الأمني عند الدخول.', 28),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.luggage_airport', 'Admission Policies', 'entry_policy', true, 'I am coming straight from the airport. Can I bring my luggage to the venue?', 'Large luggage is not permitted inside the venue. Please store your luggage before arrival. If this is not possible, contact the support team for guidance.', 'أنا قادم مباشرة من المطار. هل يمكنني إحضار حقائبي إلى الموقع؟', 'لا يُسمح بإدخال الحقائب الكبيرة إلى الموقع. يُرجى تخزين حقائبك قبل الوصول. إذا تعذر ذلك، يُرجى التواصل مع فريق الدعم للحصول على إرشادات.', 29),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'safety.unsafe_situation', 'Inside the event (Services)', 'other', true, 'I am in an uncomfortable or unsafe situation on site. What should I do?', 'Please approach any staff member wearing event identification, go to the information desk, or call the on-site safety number listed on your ticket or the event page. Your safety is the top priority.', 'أنا في موقف غير مريح أو غير آمن داخل الموقع. ماذا أفعل؟', 'يُرجى التحدث إلى أي موظف يرتدي شارة الفعالية، أو التوجه إلى مكتب المعلومات، أو الاتصال برقم الأمان الميداني المدرج على تذكرتك أو على صفحة الفعالية. سلامتك هي الأولوية القصوى.', 30),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.photo_video', 'Inside the event (Services)', 'other', false, 'What is the policy on photos and video recording?', 'Personal photography and recording for non-commercial use is permitted. Use of professional cameras and commercial recording equipment requires prior authorization.', 'ما هي سياسة التصوير والتسجيل؟', 'يُسمح بالتصوير والتسجيل الشخصي لأغراض غير تجارية. يتطلب استخدام الكاميرات الاحترافية ومعدات التسجيل التجاري إذنًا مسبقًا.', 31),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'getting_here.parking', 'Getting Here', 'other', false, 'Is parking available at the venue?', 'Yes. Parking is available near the venue. Please refer to the venue map for parking locations.', 'هل تتوفر مواقف سيارات في الموقع؟', 'نعم. تتوفر مواقف بالقرب من الموقع. يُرجى الرجوع إلى خريطة الموقع لمعرفة أماكن المواقف.', 32),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'getting_here.walking', 'Getting Here', 'other', false, 'Is the parking within walking distance of the entrance?', 'Yes. Parking areas are within walking distance of the main entrance.', 'هل المواقف على مسافة قريبة من المدخل؟', 'نعم. تقع المواقف على مسافة سير من المدخل الرئيسي.', 33),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.tiers_overview', 'Ticketing', 'ticket_availability_sold_out', false, 'What ticket tiers are available for Nightline Club?', 'Three ticket tiers are available: General Admission, VIB, and Backstage. Each tier offers a different level of access and amenities. Full details are listed on the official event page.', 'ما هي فئات التذاكر المتوفرة لفعالية Nightline Club؟', 'تتوفر ثلاث فئات من التذاكر: الدخول العام (General Admission)، والـVIB، والباكستيج (Backstage). توفر كل فئة مستوى مختلفًا من الوصول والمزايا. التفاصيل الكاملة على الصفحة الرسمية للفعالية.', 34),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.ga_inclusions', 'Ticketing', 'ticket_availability_sold_out', false, 'What does a General Admission ticket include?', 'General Admission grants entry to all public areas of the venue, including the main dancefloor.', 'ماذا تتضمن تذكرة الدخول العام؟', 'تمنح تذكرة الدخول العام حق الوصول إلى جميع المناطق العامة في الموقع، بما في ذلك الدانس فلور الرئيسي.', 35),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.vib_inclusions', 'Ticketing', 'backstage_or_vib_request', true, 'What does a VIB ticket include?', 'A VIB ticket includes all General Admission access plus entry to an elevated viewing area and dedicated bar service. Exact inclusions are listed on the event page.', 'ماذا تتضمن تذكرة الـVIB؟', 'تتضمن تذكرة الـVIB جميع امتيازات الدخول العام، بالإضافة إلى الدخول إلى منطقة مشاهدة مرتفعة وخدمة بار مخصصة. التفاصيل الدقيقة على صفحة الفعالية.', 36),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.backstage_inclusions', 'Ticketing', 'backstage_or_vib_request', true, 'What does a Backstage ticket include?', 'A Backstage ticket includes all General Admission and VIB access plus entry to the backstage area. Exact inclusions are listed on the event page.', 'ماذا تتضمن تذكرة الباكستيج؟', 'تتضمن تذكرة الباكستيج جميع امتيازات الدخول العام والـVIB، بالإضافة إلى الدخول إلى منطقة الباكستيج. التفاصيل الدقيقة على صفحة الفعالية.', 37),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.backstage_capacity', 'Ticketing', 'backstage_or_vib_request', true, 'Is there a capacity limit on Backstage access?', 'Yes. Backstage access is capacity-limited and typically sells out before other tiers.', 'هل هناك حد أقصى لعدد الحاضرين في منطقة الباكستيج؟', 'نعم. منطقة الباكستيج محدودة السعة وعادةً ما تُباع تذاكرها قبل الفئات الأخرى.', 38),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.multi_event', 'Ticketing', 'ticket_availability_sold_out', false, 'Does one ticket grant access to multiple events?', 'No. Each ticket is valid for the specific event and date printed on it.', 'هل تمنح تذكرة واحدة الوصول إلى عدة فعاليات؟', 'لا. كل تذكرة صالحة للفعالية والتاريخ المحددين عليها فقط.', 39),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.wallet_credit', 'Ticketing', 'other', true, 'How do I use wallet credit toward a purchase?', 'Wallet credit can be applied at checkout if available on your account. If the credit is not showing, please contact the support team.', 'كيف أستخدم رصيد المحفظة عند الشراء؟', 'يمكن تطبيق رصيد المحفظة عند إتمام عملية الشراء إذا كان متاحًا في حسابك. إذا لم يظهر الرصيد، يُرجى التواصل مع فريق الدعم.', 40),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.delivery_timing', 'Ticketing', 'ticket_delivery_issue', false, 'When will I receive my ticket after purchase?', 'Tickets are delivered to your account on the official ticketing platform immediately after a successful purchase. A confirmation email is sent to the email used at checkout.', 'متى سأستلم تذكرتي بعد الشراء؟', 'تُسلّم التذاكر إلى حسابك على منصة التذاكر الرسمية فور إتمام عملية الشراء بنجاح. يتم إرسال رسالة تأكيد إلى البريد الإلكتروني المستخدم عند الشراء.', 41),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.buying_for_friends', 'Ticketing', 'other', false, 'Can I buy tickets for friends?', 'Yes. You can purchase multiple tickets in a single order and transfer each one to the recipient through the official ticketing platform.', 'هل يمكنني شراء تذاكر لأصدقائي؟', 'نعم. يمكنك شراء عدة تذاكر في طلب واحد وتحويل كل تذكرة إلى المستلم عبر منصة التذاكر الرسمية.', 42),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.cancel_transfer', 'Ticketing', 'other', true, 'How do I cancel a ticket transfer I sent to a friend?', 'If the recipient has not yet accepted the transfer, you may cancel it from your account. If it has been accepted, please contact the support team.', 'كيف يمكنني إلغاء تحويل تذكرة قمت بإرسالها إلى صديق؟', 'إذا لم يقبل المستلم التحويل بعد، يمكنك إلغاؤه من حسابك. إذا تم قبوله، يُرجى التواصل مع فريق الدعم.', 43),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.offline_access', 'Ticketing', 'ticket_delivery_issue', false, 'I will not have data or Wi-Fi at the venue. How do I access my ticket?', 'Please download your ticket to your device before arriving. Once downloaded, the QR code can be displayed without an internet connection.', 'لن يكون لدي بيانات أو واي فاي في الموقع. كيف أصل إلى تذكرتي؟', 'يُرجى تنزيل تذكرتك على جهازك قبل الوصول. بعد التنزيل، يمكن عرض رمز الاستجابة السريعة دون الحاجة إلى اتصال بالإنترنت.', 44),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.reseller', 'Ticketing', 'ticket_delivery_issue', true, 'I purchased my ticket through a reseller. How do I access it?', 'If you purchased through an authorized reseller, follow the instructions in their confirmation email. If you encounter issues, contact the support team with your reseller order details.', 'اشتريت تذكرتي عبر جهة إعادة بيع. كيف أصل إليها؟', 'إذا اشتريت عبر جهة إعادة بيع معتمدة، اتبع التعليمات في رسالة التأكيد الخاصة بهم. إذا واجهت مشكلة، تواصل مع فريق الدعم مع تفاصيل طلبك.', 45),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'payment.methods_online', 'Ticketing', 'other', false, 'What payment methods are accepted online?', 'Major credit and debit cards and supported mobile wallets are accepted at checkout.', 'ما هي طرق الدفع المقبولة عبر الإنترنت؟', 'تُقبل بطاقات الائتمان والخصم الرئيسية والمحافظ الإلكترونية المدعومة عند إتمام عملية الشراء.', 46),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.group_discount', 'Ticketing', 'other', false, 'Are group discounts available?', 'Group discounts are not offered for this event.', 'هل تتوفر خصومات للمجموعات؟', 'لا تتوفر خصومات للمجموعات في هذه الفعالية.', 47),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.max_quantity', 'Ticketing', 'other', false, 'What is the maximum number of tickets I can purchase?', 'Each customer may purchase up to a defined limit per order, listed on the checkout page.', 'ما هو الحد الأقصى لعدد التذاكر التي يمكنني شراؤها؟', 'يمكن لكل عميل شراء عدد محدود من التذاكر لكل طلب، كما هو مذكور في صفحة الدفع.', 48),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.resale', 'Ticketing', 'other', true, 'Is there an official channel to resell my ticket?', 'Official ticket resale is available within the ticketing platform where supported. Tickets sold outside the official platform are not guaranteed to be valid.', 'هل توجد قناة رسمية لإعادة بيع تذكرتي؟', 'تتوفر إعادة البيع الرسمية داخل منصة التذاكر حيثما كانت مدعومة. التذاكر التي تُباع خارج المنصة الرسمية لا يُضمن صلاحيتها.', 49),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'support.contact', 'Ticketing', 'other', true, 'Who do I contact for ticket support?', 'Please contact the support team through the official channels listed on the event page, and include your order ID.', 'بمن يجب أن أتواصل للحصول على دعم بخصوص تذكرتي؟', 'يُرجى التواصل مع فريق الدعم عبر القنوات الرسمية المدرجة على صفحة الفعالية، مع تضمين رقم الطلب.', 50),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.change_details', 'Ticketing', 'other', true, 'How can I change my details after purchase?', 'Some details may be editable from your account. For changes that are not available in the platform, please contact the support team.', 'كيف يمكنني تغيير بياناتي بعد إتمام عملية الشراء؟', 'يمكن تعديل بعض التفاصيل من حسابك. للتغييرات غير المتاحة في المنصة، يُرجى التواصل مع فريق الدعم.', 51),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.change_date', 'Ticketing', 'other', true, 'Can I change my ticket to a different date?', 'Date changes are subject to the event''s transfer policy. Please contact the support team to review your options.', 'هل يمكنني تغيير تذكرتي إلى تاريخ آخر؟', 'يخضع تغيير التاريخ لسياسة التحويل الخاصة بالفعالية. يُرجى التواصل مع فريق الدعم لمراجعة الخيارات المتاحة.', 52),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.upgrade', 'Ticketing', 'ticket_upgrade_request', true, 'Can I upgrade my ticket?', 'Upgrades to a higher tier may be possible subject to availability. Please contact the support team to request an upgrade.', 'هل يمكنني ترقية تذكرتي؟', 'قد تكون ترقية التذكرة إلى فئة أعلى ممكنة وفقًا للتوفر. يُرجى التواصل مع فريق الدعم لطلب الترقية.', 53),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.upgrade_foc', 'Ticketing', 'ticket_upgrade_request', true, 'Can I upgrade a complimentary ticket to a paid tier?', 'Complimentary tickets are generally not eligible for paid upgrades. Please contact the support team for case-by-case review.', 'هل يمكنني ترقية تذكرة مجانية إلى فئة مدفوعة؟', 'التذاكر المجانية بشكل عام غير مؤهلة للترقية المدفوعة. يُرجى التواصل مع فريق الدعم للمراجعة في كل حالة على حدة.', 54),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.cancel_request', 'Ticketing', 'refund_request', true, 'Can I cancel my ticket?', 'Cancellation eligibility is determined by the event''s refund policy, which is published on the event page. Please contact the support team to review your options.', 'هل يمكنني إلغاء تذكرتي؟', 'تتحدد أهلية الإلغاء وفقًا لسياسة الاسترداد الخاصة بالفعالية المنشورة على صفحة الفعالية. يُرجى التواصل مع فريق الدعم لمراجعة الخيارات المتاحة.', 55),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.no_confirmation', 'Ticketing', 'payment_incomplete', true, 'I purchased a ticket but did not receive a confirmation email. What should I do?', 'Please check your spam folder. If you do not find the email, contact the support team with your order ID or the email address used at checkout.', 'اشتريت تذكرة لكنني لم أستلم رسالة التأكيد. ماذا أفعل؟', 'يُرجى التحقق من مجلد البريد العشوائي. إذا لم تجد الرسالة، تواصل مع فريق الدعم مع تقديم رقم الطلب أو البريد الإلكتروني المستخدم عند الشراء.', 56),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.not_received', 'Ticketing', 'ticket_delivery_issue', true, 'I have not received my ticket. What should I do?', 'Tickets are delivered to your account on the official ticketing platform. Please log in and check your tickets section. If your ticket is not there, contact the support team.', 'لم أستلم تذكرتي. ماذا أفعل؟', 'تُسلّم التذاكر إلى حسابك على منصة التذاكر الرسمية. يُرجى تسجيل الدخول والتحقق من قسم التذاكر. إذا لم تكن تذكرتك موجودة، تواصل مع فريق الدعم.', 57),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.add_more', 'Ticketing', 'other', true, 'Can I add more tickets to an order that has already been processed?', 'Once an order has been processed it cannot be modified. You may place a new order subject to availability.', 'هل يمكنني إضافة تذاكر إلى طلب تم تنفيذه بالفعل؟', 'بعد تنفيذ الطلب، لا يمكن تعديله. يمكنك تقديم طلب جديد وفقًا للتوفر.', 58),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.transfer', 'Ticketing', 'other', false, 'Are tickets transferable to family or friends?', 'Yes. Tickets can be transferred to another person through the official ticketing platform up until the event start time.', 'هل التذاكر قابلة للتحويل إلى العائلة أو الأصدقاء؟', 'نعم. يمكن تحويل التذاكر إلى شخص آخر عبر منصة التذاكر الرسمية حتى وقت بدء الفعالية.', 59),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.delivery_method', 'Ticketing', 'ticket_delivery_issue', false, 'Can I receive my ticket by email, SMS, or WhatsApp?', 'Tickets are delivered through your account on the official ticketing platform. Confirmation messages may be sent by email.', 'هل يمكنني استلام تذكرتي عبر البريد الإلكتروني أو الرسائل النصية أو الواتساب؟', 'تُسلّم التذاكر عبر حسابك على منصة التذاكر الرسمية. قد تُرسل رسائل التأكيد عبر البريد الإلكتروني.', 60),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.mail_physical', 'Ticketing', 'ticket_delivery_issue', false, 'Can my ticket be mailed to me as a physical copy?', 'No. Tickets are digital only.', 'هل يمكن إرسال تذكرتي بالبريد كنسخة ورقية؟', 'لا. التذاكر رقمية فقط.', 61),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'ticket.upload_issue', 'Ticketing', 'ticket_delivery_issue', true, 'My ticket is not loading in the app. What should I do?', 'Please ensure you are logged in with the email used at purchase and that the app is updated to the latest version. If the issue persists, contact the support team.', 'تذكرتي لا تظهر في التطبيق. ماذا أفعل؟', 'يُرجى التأكد من تسجيل الدخول بالبريد الإلكتروني المستخدم عند الشراء وأن التطبيق محدّث إلى أحدث إصدار. إذا استمرت المشكلة، تواصل مع فريق الدعم.', 62),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.refund.standard', 'Ticketing', 'refund_request', true, 'What is the refund policy for Nightline Club?', 'All ticket sales are final. Refunds are not issued except where required by applicable consumer protection law or in cases of event cancellation. Refund eligibility is reviewed on a case-by-case basis by the support team.', 'ما هي سياسة استرداد المبالغ لفعالية Nightline Club؟', 'جميع مبيعات التذاكر نهائية. لا يتم استرداد المبالغ إلا في الحالات التي يقتضيها قانون حماية المستهلك المعمول به أو في حالات إلغاء الفعالية. يُراجع فريق الدعم أهلية الاسترداد لكل حالة على حدة.', 63),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.refund.medical', 'Ticketing', 'refund_request', true, 'I cannot attend due to a medical reason. Can I get a refund?', 'Medical exceptions are reviewed on a case-by-case basis with valid supporting documentation. Please contact the support team in advance of the event.', 'لا أستطيع الحضور بسبب ظرف صحي. هل يمكنني استرداد قيمة التذكرة؟', 'تُراجع الاستثناءات الصحية لكل حالة على حدة مع تقديم وثائق ثبوتية صالحة. يُرجى التواصل مع فريق الدعم قبل موعد الفعالية.', 64),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.refund.denied_entry', 'Ticketing', 'refund_request', true, 'I was denied entry due to dress code or age policy. Can I get a refund?', 'Entry decisions made by venue security are final. Refunds are not typically issued for denied entry due to policy violations. Each case is reviewed individually by the support team.', 'تم منعي من الدخول بسبب الزي أو سياسة العمر. هل يمكنني استرداد قيمة التذكرة؟', 'قرارات الدخول التي يتخذها فريق أمن الموقع نهائية. لا تُسترد عادةً قيمة التذاكر في حالات منع الدخول بسبب مخالفة السياسات. يُراجع فريق الدعم كل حالة على حدة.', 65),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'policy.refund.event_change', 'Ticketing', 'compensation_request', true, 'The event lineup or date has changed. Am I eligible for a refund?', 'If the event has been materially changed, ticket holders may be eligible for a refund or compensation. The support team will reach out with the available options, or you can contact them directly.', 'تم تغيير قائمة الفنانين أو تاريخ الفعالية. هل أنا مؤهل لاسترداد المبلغ؟', 'إذا تم إجراء تغيير جوهري على الفعالية، قد يكون حاملو التذاكر مؤهلين لاسترداد المبلغ أو الحصول على تعويض. سيتواصل فريق الدعم معك بالخيارات المتاحة، أو يمكنك التواصل معهم مباشرة.', 66),
  ('7aac29a8-0a1d-5341-b472-d027b66ba72b', '4b6d73f4-2e51-5c69-a411-da7ce0be6d14', 'reservation.table', 'Ticketing', 'reservation_followup', true, 'I requested a table reservation but have not heard back. What should I do?', 'Table reservation requests are reviewed individually. If you have not received a response within the timeframe stated at the time of request, please contact the support team with your reservation reference.', 'قدمت طلب حجز طاولة لكنني لم أتلق ردًا. ماذا أفعل؟', 'تُراجع طلبات حجز الطاولات بشكل فردي. إذا لم تتلقَ ردًا خلال الفترة المذكورة وقت تقديم الطلب، يُرجى التواصل مع فريق الدعم مع تقديم رقم مرجع الحجز.', 67)
ON CONFLICT (event_id, section_id) DO UPDATE SET
  category = EXCLUDED.category,
  intent = EXCLUDED.intent,
  escalation_needed = EXCLUDED.escalation_needed,
  question_en = EXCLUDED.question_en,
  answer_en = EXCLUDED.answer_en,
  question_ar = EXCLUDED.question_ar,
  answer_ar = EXCLUDED.answer_ar,
  sort_order = EXCLUDED.sort_order;

